return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'nb_NO','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Oppdater programtillegget TranslatePress - Multilingual til versjon %1$s eller høyere for å sikre at %2$s fungerer korrekt.','Please install and activate the TranslatePress - Multilingual plugin'=>'Installer og aktiver programtillegget TranslatePress - Multilingual','Install & Activate'=>'Installer og aktiver','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Oppdater TranslatePress - Multilingual til versjon %2$s eller nyere. Din installerte versjon av TranslatePress - Multilingual er ikke lenger kompatibel med den gjeldende versjonen av %1$s.','All TranslatePress functionalities are disabled until then.'=>'Alle TranslatePress-funksjoner er deaktivert frem til da.','Update Now'=>'Oppdater nå','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Dette TranslatePress-tillegget er overført til hovedprogramtillegget og brukes ikke lenger. Du kan slette det.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> krever minst PHP-versjon 5.6.20+ for å kjøre. Det er <a href="%s">minimumskravet til den nyeste WordPress-versjonen</a>. Kontakt serveradministratoren din for å oppdatere PHP-versjonen din.','Advanced'=>'Avansert','Settings saved.'=>'Innstillinger lagret.','Are you sure you want to remove this item?'=>'Er du sikker på at du vil fjerne dette elementet?','Remove'=>'Fjern','Add'=>'Legg til','Select...'=>'Velg...','[%s] Low TranslatePress AI Words'=>'[%s] Få TranslatePress AI-ord igjen','upgrade your plan or get extra AI Words'=>'oppgrader planen din eller skaff ekstra AI-ord','upgrade your plan'=>'oppgrader planen din','TranslatePress AI words are running low on your site.'=>'Det er få TranslatePress AI-ord igjen på nettstedet ditt.','Current status: %s words remaining'=>'Gjeldende status: %s ord igjen','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Når de gjenværende AI-ordene tar slutt, vil automatisk oversettelse via TranslatePress AI bli satt på pause.','To continue translating your content, please %1$s over at %2$s'=>'For å fortsette å oversette innholdet ditt, vennligst %1$s på %2$s','Manage Notification: %s'=>'Behandle varsling: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Det er en ny versjon av %1$s tilgjengelig. %2$sVis detaljer for versjon %3$s%4$s eller %5$soppdater nå%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Det er en ny versjon av %1$s tilgjengelig. %2$sVis detaljer for versjon %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'For å aktivere oppdateringer, vennligst %1$sskriv inn lisensnøkkelen din%2$s. Trenger du en lisensnøkkel? %3$sKjøp en nå%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'For å aktivere oppdateringer, gå til %1$slisensiden%2$s og sjekk at du har en gyldig lisens.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'For å aktivere oppdateringer, må lisensen din fornyes. Vennligst gå til siden %1$sTranslatePress Account%2$s og logg inn for å fornye.','You do not have permission to install plugin updates'=>'Du har ikke tillatelse til å installere oppdateringer for programtillegg.','Error'=>'Feil','Your TranslatePress license key is invalid or missing.'=>'TranslatePress-lisensnøkkelen din er ugyldig eller mangler.','Your license key expired on %s.'=>'Lisensnøkkelen din utløp %s.','Your license key has been disabled.'=>'Lisensnøkkelen din er deaktivert.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Lisensnøkkelen din er deaktivert for denne URL-en. Aktiver den på nytt fra <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrer nettsteder.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Lisensnøkkelen stemmer ikke overens.</strong> Lisensen du skrev inn, samsvarer ikke med TranslatePress-versjonen du har installert.</p><p>Sjekk at du har installert riktig versjon for lisensen din fra TranslatePress-kontoen din.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Hvis du bare har det gratis programtillegget installert, men har lagt til en betalt lisens, installer det betalte programtillegget fra TranslatePress-kontoen din.','Your license key has reached its activation limit.'=>'Lisensnøkkelen din har nådd aktiveringsgrensen.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Oppgrader planen din for å legge til flere nettsteder. %1$sOppgrader nå%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Dette nettstedet er allerede aktivert med en gratis lisens. Hvert nettsted kan bare bruke én gratis lisens.','An error occurred, please try again.'=>'Det oppstod en feil, vennligst prøv igjen.','You have successfully activated your license'=>'Du har aktivert lisensen din.','Others'=>'Andre','Restrict by Language'=>'Begrens etter språk','Exclude from Language'=>'Ekskluder fra språk','Restrict element to language'=>'Begrens element til språk','Show this element only in one language.'=>'Vis dette elementet bare på ett språk.','Enable translation'=>'Aktiver oversettelse','Allow translation to the corresponding language only if the content is written in the default language.'=>'Tillat oversettelse til det aktuelle språket bare hvis innholdet er skrevet på standardspråket.','Select language'=>'Velg språk','Choose in which language to show this element.'=>'Velg hvilket språk dette elementet skal vises på.','Exclude element from language'=>'Ekskluder element fra språk','Exclude this element from specific languages.'=>'Ekskluder dette elementet fra spesifikke språk.','Select languages'=>'Velg språk','Choose from which languages to exclude this element.'=>'Velg hvilke språk dette elementet skal ekskluderes fra.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Dette elementet vil fortsatt være synlig når du oversetter nettstedet ditt via oversettelsesredigereren.','The content of this element should be written in the default language.'=>'Innholdet i dette elementet skal være skrevet på standardspråket.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> oppdaget SQL-feil. <a href="%s" title="View TranslatePress SQL Errors">Se feilene</a>.','Automatic translation has been disabled.'=>'Automatisk oversettelse er deaktivert.','Dismiss this notice.'=>'Lukk dette varselet.','Logged errors'=>'Loggførte feil','These are the most recent 5 errors logged by TranslatePress:'=>'Dette er de 5 siste feilene loggført av TranslatePress:','Yes'=>'Ja','Why are these errors occuring'=>'Hvorfor oppstår disse feilene','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Hvis TranslatePress oppdager noe galt under kjøring av spørringer i databasen din, kan den deaktivere funksjonen for automatisk oversettelse for å unngå ekstra kostnader fra Google/DeepL. Funksjonen for automatisk oversettelse må slås på manuelt etter at du har løst problemene.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'De oppdagede SQL-feilene kan oppstå av ulike grunner, blant annet manglende tabeller, manglende tillatelser for SQL-brukeren til å opprette tabeller eller utføre andre operasjoner, problemer etter nettstedsmigrering eller endringer i konfigurasjonen til SQL-serveren.','What you can do in this situation'=>'Hva du kan gjøre i denne situasjonen','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Gå til Innstillinger -> TranslatePress -> fanen Generelt og lagre innstillingene. Dette vil regenerere tabellene ved hjelp av dine gjeldende SQL-innstillinger. Sjekk at det ikke oppstår flere feil mens du surfer på nettstedet ditt på et oversatt språk. Se på tidsstemplene til feilene for å forsikre deg om at du ikke ser de gamle feilene. Kun de 5 siste feilene vises.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Hvis problemet ikke er løst, prøv følgende trinn:','Create a backup of your database'=>'Opprett en sikkerhetskopi av databasen din','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Opprett en kopi av hver oversettelsestabell der du støter på feil. Du kan kopiere tabellen i samme database (trp_dictionary_en_us_es_es_COPY for eksempel) -- utfør dette steget kun hvis du vil beholde gjeldende oversettelser.','Remove the trouble tables by executing the DROP function on them'=>'Fjern problem-tabellene ved å kjøre DROP-funksjonen på dem','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Gå til Innstillinger -> TranslatePress -> fanen Generelt og lagre innstillingene. Dette vil regenerere tabellene ved hjelp av din gjeldende SQL-server.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopier det relevante innholdet fra de dupliserte tabellene (trp_dictionary_en_us_es_es_COPY for eksempel) til den nygenererte tabellen (trp_dictionary_en_us_es_es) -- utfør dette steget kun hvis du vil beholde gjeldende oversettelser.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Test det for å se om alt fungerer. Hvis noe gikk galt, kan du gjenopprette sikkerhetskopien du opprettet i første steg. Sjekk at det ikke oppstår flere feil mens du surfer på nettstedet ditt på et oversatt språk. Se på tidsstemplene til feilene for å forsikre deg om at du ikke ser de gamle feilene. Kun de 5 siste feilene vises.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Hvis problemet fremdeles ikke er løst, prøv å spørre vertsleverandøren din om feilene. Det vanligste problemet er manglende tillatelser for SQL-brukeren, for eksempel tillatelsen til å opprette tabeller.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Kunne ikke installere. Prøv igjen fra <a href="%s" >Utvidelsesdashbordet.</a>','Active'=>'Aktiv','Permission denied.'=>'Tilgang nektet.','Invalid nonce.'=>'Ugyldig nonce.','Settings scope unknown.'=>'Ukjent innstillingsomfang.','Legacy disabled.'=>'Eldre modus deaktivert.','Language Switcher'=>'Språkvelger','Change language to %s'=>'Endre språk til %s','Automatic Translation'=>'Automatisk oversettelse','DeepL'=>'DeepL','Unsupported languages'=>'Ikke-støttede språk','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Den valgte automatiske oversettelsesmotoren støtter ikke disse språkene.<br>Du kan fortsatt manuelt oversette sider på disse språkene ved hjelp av oversettelseseditoren.','API key validation failed.'=>'API-nøkkelvalidering mislyktes.','API key verification was successful.'=>'API-nøkkelen ble bekreftet.','Please enter your Google Translate key.'=>'Vennligst skriv inn Google Translate-nøkkelen din.','Please enter your DeepL API key.'=>'Vennligst skriv inn DeepL API-nøkkelen din.','Not TranslatePress onboarding page.'=>'Ikke en TranslatePress-oppsettsside.','Step %s does not exist'=>'Trinn %s finnes ikke','Welcome'=>'Velkommen','Add Languages'=>'Legg til språk','Enable Addons'=>'Aktiver tillegg','Finalize'=>'Fullfør','Exit Setup'=>'Avslutt oppsett','Upgrade'=>'Oppgrader','Nothing here'=>'Ingenting her','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Lisensen din for <strong>TranslatePress</strong> mangler eller er ugyldig. <br/>Vennligst %1$sregistrer kopien din%2$s for å aktivere automatisk nettstedsoversettelse via TranslatePress AI, premium-tillegg, automatiske oppdateringer og støtte. Trenger du en lisensnøkkel? %3$sKjøp en nå%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Lisensen din for <strong>TranslatePress</strong> utløper %1$s. Vennligst %2$sforny lisensen din%3$s for å fortsette å ha tilgang til automatiske oversettelser via TP AI, premium-tillegg, produktnedlastinger og automatiske oppdateringer. %4$sForny nå%5$s','Error: '=>'Feil: ','Something went wrong, please try again.'=>'Noe gikk galt, vennligst prøv igjen.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Lisensen din for <strong>TranslatePress</strong> har utløpt. <br/>Vennligst %1$sforny lisensen din%2$s for å fortsette å ha tilgang til automatiske oversettelser via TranslatePress AI, premium-tillegg, produktnedlastinger og automatiske oppdateringer. %3$sForny nå %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Lisensnøkkelen stemmer ikke. Lisensen du oppga samsvarer ikke med <strong>%1$s</strong>-versjonen du har installert. <br/>Sjekk at du har installert riktig versjon for lisensen din fra %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Hvis du bare har den gratis utvidelsen installert, men har lagt til en betalt lisens, installer den betalte utvidelsen fra TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Du har nådd aktiveringsgrensen for <strong>%1$s</strong>-lisensen din. <br/>Administrer aktive nettsteder fra %2$skontoen din%3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Lisensen din er deaktivert for denne URL. Aktiver den på nytt fra <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrer nettsteder.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Automatisk oversettelse med %1$s krever en aktiv lisens. Vennligst %2$sforny%3$s lisensen din eller kjøp en ny %4$sher%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Vennligst %1$sskriv inn%2$s lisensnøkkelen din for å aktivere automatisk oversettelse med %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Du har mindre enn 5 000 TranslatePress AI-ord igjen. For å fortsette å oversette nettstedet ditt automatisk, vennligst %skjøp flere AI-ord med rabatt fra kontoen din%s.',' Error: '=>' Feil: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Dette nettstedet er allerede aktivert med en gratis lisens. Hvert nettsted kan bare bruke én gratis lisens. Oppgrader til en premium-plan for flere TranslatePress AI-ord fra %1$skontoen din%2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Du har ikke en gyldig lisens for <strong>TranslatePress</strong>. %1$sFå en gratis%2$s for å få tilgang til TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NYTT:</strong> Tillegget <strong>Different Domain per Language</strong> er her! Forbedre din globale SEO og skap en lokal opplevelse med landsspesifikke domener som .de eller .fr. Oppgrader til <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business eller Developer</a> for å få tilgang til det og flere premium-fordeler!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NYTT:</strong> Tillegget <strong>Different Domain per Language</strong> er her! Forbedre din globale SEO og skap en lokal opplevelse med landsspesifikke domener som .de eller .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Les mer</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Den daglige kvoten for tegn i maskinoversettelse er overskredet. Sjekk siden <strong>TranslatePress -> <a href="%s">Automatisk oversettelse</a></strong> for mer informasjon.','Marketing optin'=>'Markedsføringssamtykke','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Samtykk til varsler om sikkerhets- og funksjonsoppdateringer, samt ikke-sensitiv diagnostisk sporing.','TranslatePress Preferred User Language'=>'TranslatePress foretrukket brukerspråk','Preferred language to navigate the site'=>'Foretrukket språk for å navigere på nettstedet','The language is automatically set based by the last visited language by the user.'=>'Språket settes automatisk basert på det siste språket brukeren besøkte.','Always use this language'=>'Bruk alltid dette språket','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Ved å merke av denne innstillingen vil det foretrukne språket forbli det som er valgt ovenfor, uten at det kan endres i frontend.<br>Dette språket vil brukes i ulike operasjoner, for eksempel ved sending av e-post til brukeren.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hei! Det ser ut som du har brukt <strong>TranslatePress</strong> en stund nå for å oversette nettstedet ditt. Det er kjempebra! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Hvis du kan avse noen minutter til å vurdere det på WordPress.org, vil det hjelpe oss mye (og øke motivasjonen min).','~ Razvan, developer of TranslatePress'=>'~ Razvan, utvikler av TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Vurder TranslatePress på WordPress.org','Ok, I will gladly help!'=>'OK, jeg hjelper gjerne!','No, thanks.'=>'Nei, takk.','Full Language Names'=>'Fullstendige språknavn','Short Language Names'=>'Korte språknavn','Flags with Full Language Names'=>'Flagg med fullstendige språknavn','Flags with Short Language Names'=>'Flagg med korte språknavn','Only Flags'=>'Kun flagg','Full Language Names No HTML'=>'Fullstendige språknavn uten HTML','Bottom Right'=>'Nede til høyre','Bottom Left'=>'Nederst til venstre','Top Right'=>'Øverst til høyre','Top Left'=>'Øverst til venstre','Dark'=>'Mørk','Light'=>'Lys','Deactivate'=>'Deaktiver','Activate'=>'Aktiver','Invalid language code. Please try again.'=>'Ugyldig språkkode. Prøv igjen.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Språkkoder kan bare inneholde tegnene A-Z a-z 0-9 - _. Sjekk språkkodene dine i de generelle innstillingene i TranslatePress.','Error! Duplicate URL slug values.'=>'Feil! Dupliserte URL slug-verdier.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Du kan ikke velge to språk som har samme <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO-kode</a> men ulike formaliteter, fordi dette vil føre til dupliserte <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang-tagger</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Duplisert språk oppdaget.<br>Hvert språk kan bare legges til én gang for å sikre nøyaktig oversettelsesstyring.<br> Endre den dupliserte språkoppføringen og prøv igjen. ','Current Language'=>'Gjeldende språk','Opposite Language'=>'Motsatt språk','General'=>'Generelt','Translate Site'=>'Oversett nettsted','Addons'=>'Tillegg','License'=>'Lisens','Settings'=>'Innstillinger','Activate License'=>'Aktiver lisens','Pro Features'=>'Pro-funksjoner','Need Help?'=>'Trenger du hjelp?','Recent community discussions'=>'Nylige fellesskapsdiskusjoner','Loading...'=>'Laster...','Unable to load forum posts'=>'Kan ikke laste foruminnlegg','Ask a Question'=>'Still et spørsmål','View All Topics'=>'Vis alle emner','by'=>'av','Have a question?'=>'Har du et spørsmål?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Få hjelp direkte fra utviklerne av utvidelsen, foreslå forbedringer eller del tilbakemeldingen din!','Tip for faster help:'=>'Tips for raskere hjelp:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Inkluder hva du prøvde, hva du forventet og hva som skjedde. Skjermbilder hjelper!','Toggle support chat'=>'Veksle supportchat','Ask the community'=>'Spør fellesskapet','Close'=>'Lukk','Empty feed response'=>'Tomt feed-svar','Unable to parse feed'=>'Kan ikke tolke feed','Just now'=>'Akkurat nå','%d hour ago'=>'%d time siden' . "\0" . '%d timer siden','%d day ago'=>'%d dag siden' . "\0" . '%d dager siden','Source'=>'Kilde','Srcset'=>'Srcset','Alt attribute'=>'Alt-attributt','Title attribute'=>'Tittelattributt','Anchor link'=>'Ankerlenke','Placeholder attribute'=>'Plassholder-attributt','Submit attribute'=>'Submit-attributt','Text'=>'Tekst','Video Poster'=>'Plakatbilde','plural form'=>'Flertallsform','one'=>'Entall','few'=>'Få','many'=>'Mange','other'=>'Annet','Saved'=>'Lagret','Save'=>'Lagre','Saving translation...'=>'Lagrer oversettelse...','You have unsaved changes!'=>'Du har ulagrede endringer!','Discard changes'=>'Forkast endringer','Discard All'=>'Forkast alle','Loading Strings...'=>'Laster strenger...','Select string to translate...'=>'Velg streng å oversette...','Close Editor'=>'Lukk editor','From'=>'Fra','To'=>'Til','Add Media'=>'Legg til medium','Other languages'=>'Andre språk','Context'=>'Kontekst','View Website As'=>'Vis nettsted som','Available in our Pro Versions'=>'Tilgjengelig i Pro-versjonene våre','Select or Upload Media'=>'Velg eller last opp medium','Use this media'=>'Bruk dette mediet','Translate'=>'Oversett','Translate entire block element'=>'Oversett hele blokkelementet','Split block to translate strings individually'=>'Del opp blokken for å oversette strenger enkeltvis','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Lagre endringer i oversettelsen. Snarvei: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Naviger til neste streng i nedtrekkslisten. Snarvei: CTRL(⌘) + ALT + høyrepil','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Naviger til forrige streng i nedtrekkslisten. Snarvei: CTRL(⌘) + ALT + venstrepil','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Forkast alle endringer. Snarvei: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Forkast endringer i dette tekstfeltet. For å forkaste endringer i alle tekstfelt bruker du snarveien: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Lukk verktøytips','Quick Intro'=>'Kort introduksjon','Are you sure you want to split this phrase into smaller parts?'=>'Er du sikker på at du vil dele denne frasen i mindre deler?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Denne strengen er ikke klar for oversettelse ennå. <br>Prøv igjen om et øyeblikk...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'For at dette alternativet skal fungere, oppdater tillegget Browse as other role til den nyeste versjonen.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'For å oversette slugs, oppdater tillegget SEO Pack til den nyeste versjonen.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Du kan legge til et nytt språk fra <a href="%s">Innstillinger->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Du kan imidlertid fortsatt bruke TranslatePress til å endre <strong style="background: #f5fb9d;">Gettext-strenger</strong> som er tilgjengelige på siden din.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Brukeropprettede strenger kan ikke endres, kun de fra temaer og tillegg.','Extra Translation Features'=>'Ekstra oversettelsesfunksjoner','Support for 130+ Extra Languages'=>'Støtte for 130+ ekstra språk','Access to TranslatePress AI'=>'Tilgang til TranslatePress AI','Translate SEO Title, Description, Slug'=>'Oversett SEO-tittel, beskrivelse og slug','Publish only when translation is complete'=>'Publiser bare når oversettelsen er fullført','Translate by Browsing as User Role'=>'Oversett ved å bla gjennom som brukerrolle','Different Menu Items for each Language'=>'Ulike menyelementer for hvert språk','Automatic User Language Detection'=>'Automatisk gjenkjenning av brukerspråk','Upgrade to PRO'=>'Oppgrader til PRO','Upgrade to PRO with our biggest discount of the year!'=>'Oppgrader til PRO med årets største rabatt!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Denne Black Friday får du tilgang til disse funksjonene og mer til, til en brøkdel av prisen:','No available suggestions'=>'Ingen tilgjengelige forslag','Suggestions from translation memory'=>'Forslag fra oversettelsesminnet','Click to Copy'=>'Klikk for å kopiere','Human Translation'=>'Menneskelig oversettelse','Machine Translation'=>'Maskinoversettelse','Text on this page is %s% translated into all languages.'=>'Teksten på denne siden er %s % oversatt til alle språk.','%1$s% of text on this page is translated into %2$s.'=>'%1$s % av teksten på denne siden er oversatt til %2$s.','This page is %1$s% translated into %2$s.'=>'Denne siden er %1$s % oversatt til %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Sluggen du prøver å redigere, finnes i andre slugtyper:%s%. Å redigere den vil erstatte hver forekomst, uavhengig av gjeldende type.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Hold musepekeren over tekst på siden, klikk %s,<br> og endre oversettelsen i sidefeltet.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Ikke glem å lagre oversettelsen. Bruk tastatursnarveien CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Bytt språk for å se endringene i oversettelsen direkte på siden.','Search for any text in this page in the dropdown.'=>'Søk etter tekst på denne siden i nedtrekksmenyen.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Din %s-lisens har <span class="trp-license-status-emphasized">utløpt</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Forny lisensen din for å fortsette å ha tilgang til TranslatePress AI, premiumtillegg, automatiske oppdateringer og støtte.','Renew Now'=>'Forny nå','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Denne Black Friday kan du fornye lisensen din til spesialpris</strong> for å fortsette å ha tilgang til produktnedlastinger, automatiske oppdateringer og støtte.','Get Deal'=>'Få tilbudet','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Din %s-lisens ble <span class="trp-license-status-emphasized">refundert</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Kjøp en ny lisens for å fortsette å ha tilgang til TranslatePress AI, premiumtillegg, automatiske oppdateringer og støtte.','Purchase a new license'=>'Kjøp en ny lisens','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Din %s-lisens er <span class="trp-license-status-emphasized">manglende eller ugyldig</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Vennligst angi en gyldig lisens for å få tilgang til TranslatePress AI, premium tillegg, automatiske oppdateringer og brukerstøtte. Trenger du en lisensnøkkel? %1$sKjøp en nå%2$s','Enter a valid license'=>'Angi en gyldig lisens','Slugs'=>'Slugs','Meta Information'=>'Metainformasjon','String List'=>'Strengliste','Gettext Strings'=>'Gettext-strenger','Images'=>'Bilder','Videos'=>'Videoer','Audios'=>'Lydfiler','Dynamically Added Strings'=>'Dynamisk tilføyde strenger','Translation Editor'=>'Oversettelseseditor','Edit translations by visually selecting them on each site page'=>'Rediger oversettelser ved å velge dem visuelt på hver nettside','String Translation'=>'Strengoversettelse','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Rediger oversettelser av URL slugs, tillegg og temaer (e-poster, skjemaer osv.)','Current User'=>'Gjeldende bruker','Logged Out'=>'Logget ut','Translate Page'=>'Oversett side','Add a New Language'=>'Legg til et nytt språk','Get a Free AI License'=>'Få en gratis AI-lisens','Your License is Invalid'=>'Lisensen din er ugyldig','Get More AI Words (%d left)'=>'Få flere AI-ord (%d igjen)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Åpner innlegget i oversettelseseditoren. Innlegget må være lagret som kladd eller publisert på forhånd.','Security check'=>'Sikkerhetskontroll','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Advarsel:</strong> Noen strenger har tegn som muligens er feilkodet. Dette kan føre til brudd i spørringene, slik at siden vises uoversatt i live-modus. Vurder å revidere følgende strenger eller måten de skrives ut på.','TranslatePress data update'=>'Oppdatering av TranslatePress-data','We need to update your translations database to the latest version.'=>'Vi må oppdatere oversettelsesdatabasen din til den nyeste versjonen.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Oppdateringen gjør det mulig å redigere oversettelser av lokalisert tekst fra utvidelser og tema. Eksisterende oversettelser vil fortsatt fungere som forventet.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'VIKTIG: Det anbefales på det sterkeste å først ta sikkerhetskopi av databasen!
Er du sikker på at du vil fortsette?','Run the updater'=>'Kjør oppdateringen','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Oppdatering vil tillate redigering av oversettelser av slug. Eksisterende oversettelse vil fortsatt fungere som forventet.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Vennligst aktiver SEO-tillegget fra <br/>WordPress -> Innstillinger -> TranslatePress -> Tillegg-delen','Go to Addons'=>'Gå til Tillegg','The SEO Pack add-on allows translation of all the URL slugs:'=>'SEO Pack-tillegget gjør det mulig å oversette alle URL-slug:','Taxonomy slugs'=>'Slug for taksonomier','Term slugs'=>'Slug for termer','Post slugs (this includes pages and custom post types)'=>'Slug for innlegg (dette inkluderer sider og egendefinerte innleggstyper)','Post type base slugs'=>'Base-slug for innleggstyper','WooCommerce slugs'=>'WooCommerce-slug','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'SEO Pack-tillegget er tilgjengelig med ALLE premiumversjoner av programtillegget.','Upgrade to Pro'=>'Oppgrader til Pro','Description'=>'Beskrivelse','Article Section'=>'Artikkel-seksjon','Article Tag'=>'Artikkel-stikkord','OG Title'=>'OG-tittel','OG Site Name'=>'OG-nettstedsnavn','OG Description'=>'OG-beskrivelse','OG Image Alt'=>'OG-bilde-alt','Twitter Title'=>'Twitter-tittel','Twitter Description'=>'Twitter-beskrivelse','Twitter Image Alt'=>'Twitter-bilde-alt','Page Title'=>'Sidetittel','Dublin Core Title'=>'Dublin Core-tittel','Dublin Core Description'=>'Dublin Core-beskrivelse','OG Image'=>'OG-bilde','OG Image Secure URL'=>'Sikker URL for OG-bilde','Twitter Image'=>'Twitter-bilde','Removing cdata dictionary strings for language %s...'=>'Fjerner CDATA-ordboksstrenger for språket %s...','Removing untranslated dictionary links for language %s...'=>'Fjerner uoversatte ordbokslenker for språket %s...','Removing duplicated gettext strings for language %s...'=>'Fjerner dupliserte Gettext-strenger for språket %s...','Removing duplicated dictionary strings for language %s...'=>'Fjerner dupliserte ordboksstrenger for språket %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Fjerner uoversatte ordboksstrenger der oversettelse er tilgjengelig for språket %s...','Inserting original strings for language %s...'=>'Setter inn originalstrenger for språket %s...','Cleaning original strings table for language %s...'=>'Rydder tabellen for originalstrenger for språket %s...','Updating original string ids for language %s...'=>'Oppdaterer ID-er for originalstrenger for språket %s...','Regenerating original meta table for language %s...'=>'Regenererer tabellen for original-meta for språket %s...','Cleaning original meta table for language %s...'=>'Renser tabellen for original-meta for språket %s...','Replacing original id NULL with value for language %s...'=>'Erstatter original-ID NULL med verdi for språket %s...','Inserting gettext original strings for language %s...'=>'Setter inn Gettext-originalstrenger for språket %s...','Cleaning gettext original strings table for language %s...'=>'Rydder tabellen for Gettext-originalstrenger for språket %s...','Updating gettext original string ids for language %s...'=>'Oppdaterer ID-er for Gettext-originalstrenger for språket %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Migrerer slug for taksonomier og base-slug for innleggstyper til ny tabellstruktur...','Migrating post slugs to new table structure for language %s...'=>'Migrerer slug for innlegg til ny tabellstruktur for språket %s...','Migrating term slugs to new table structure for language %s...'=>'Migrerer term-slug til ny tabellstruktur for språk %s...','Finishing up...'=>'Fullfører...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Databaseoptimaliseringen ble ikke fullført. Vi anbefaler å gjenopprette den originale databasen eller <a href="%s" >prøve på nytt.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Oppdatering avbrutt! Brukerkontoen din har ikke rettigheter til å utføre databaseoppdateringer.','Update aborted! Invalid nonce.'=>'Oppdatering avbrutt! Ugyldig nonce.','Update aborted! Incorrect action.'=>'Oppdatering avbrutt! Feil handling.','Update aborted! Incorrect language code.'=>'Oppdatering avbrutt! Feil språkkode.','Updating database to version %s+'=>'Oppdaterer database til versjon %s+','Processing table for language %s...'=>'Behandler tabell for språk %s...','Back to TranslatePress Settings'=>'Tilbake til TranslatePress-innstillinger','Successfully updated database!'=>'Databasen ble oppdatert!',' done.'=>' fullført.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Alle individuelle TranslatePress-tilleggsprogrammer <a href="%1$s" target="_blank">er avviklet</a> og er nå inkludert i premiumversjonene Personal, Business og Developer av TranslatePress. Logg inn på <a href="%2$s" target="_blank">kontosiden</a> din, last ned den nye premiumversjonen og installer den. Innstillingene dine for individuelle tillegg vil bli overført.','Brand-new Language Switcher Settings are here!'=>'Helt nye innstillinger for språkbytter er her!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Utforsk ferdiglagde maler, bytt farger, flaggstiler, avstand, oppsett og mer. Bruk forhåndsvisning i sanntid for å perfeksjonere bytteren på sekunder.','Start customizing'=>'Begynn å tilpasse','Read documentation'=>'Les dokumentasjon','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> krever <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP-biblioteket</a></strong>. Kontakt serveradministratoren din for å installere det på serveren din.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Oppdaget begrensning for lange spørringer på WPEngine-hosting. Noen store sider kan vises uoversatt. Du kan fjerne begrensningen ved å legge til følgende i nettstedets wp-config.php: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Egendefinert språkflagg','The Language code of the added custom language cannot be empty.'=>'Språkkoden for det egendefinerte språket som ble lagt til kan ikke være tom.','The Language code of the added custom language is invalid.'=>'Språkkoden for det egendefinerte språket som ble lagt til er ugyldig.','The Automatic Translation Code of the added custom language is invalid.'=>'Koden for automatisk oversettelse for det egendefinerte språket som ble lagt til er ugyldig.','TranslatePress Add-ons'=>'TranslatePress-tillegg','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Du må først kjøpe denne versjonen for å få tilgang til tillegget %1$sher%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Vennligst %1$sangi din lisens%2$s nøkkel først for å aktivere denne utvidelsen.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Du trenger en aktiv lisens for å få tilgang til utvidelsen. Forny eller kjøp en ny %1$sher%2$s.','Advanced Add-ons'=>'Avanserte tillegg','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Disse utvidelsene utvider oversettelsesprogramtillegget ditt og er tilgjengelige i planene Developer, Business og Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (eldre)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-støtte for side-slug, sidetittel, beskrivelse og sosial graf-informasjon for Facebook og Twitter. HTML lang-attributtet er satt korrekt.','Multiple Languages'=>'Flere språk','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Legg til så mange språk du trenger for at prosjektet ditt skal nå ut globalt. Publiser kun språket ditt når alle oversettelsene er ferdige.','Pro Add-ons'=>'Pro-utvidelser','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Disse utvidelsene utvider oversettelsesprogramtillegget ditt og er tilgjengelige i planene Business og Developer.','DeepL Automatic Translation'=>'Automatisk oversettelse med DeepL','Automatically translate your website through the DeepL API.'=>'Oversett nettstedet ditt automatisk via DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Oppfordrer besøkende til å bytte til deres foretrukne språk basert på nettleserinnstillinger eller IP-adresse, og husker det sist besøkte språket.','Translator Accounts'=>'Oversetterkontoer','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Opprett oversetterkontoer for nye brukere, eller la eksisterende brukere som ikke er administratorer oversette nettstedet ditt.','Browse As User Role'=>'Bla igjennom som brukerrolle','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Naviger på nettstedet ditt akkurat som en bestemt brukerrolle ville gjort. Veldig nyttig for dynamisk innhold eller skjult innhold som vises for bestemte brukere.','Navigation Based on Language'=>'Navigasjon basert på språk','Configure different menu items for different languages.'=>'Konfigurer ulike menyelementer for ulike språk.','Different Domain per Language'=>'Eget domene per språk','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Koble separate domener eller underdomener til hver av dine oversatte versjoner. Styrk merkevarens lokale identitet og forbedre SEO-ytelsen for hvert språk du støtter.','Recommended Plugins'=>'Anbefalte utvidelser','A short list of plugins you can use to extend your website.'=>'En kort liste med utvidelser du kan bruke til å utvide nettstedet ditt.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Samle inn mer brukerinformasjon i registreringsskjemaet ved hjelp av egendefinerte brukerprofilfelt fra Profile Builder, og/eller legg til en e-postbekreftelsesprosess for å bekrefte kundenes kontoer.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Ta imot betalinger fra brukere, opprett abonnementsplaner og begrens innhold på medlemsnettstedet ditt.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Opprett automatiseringer og arbeidsflyter uten kode på WordPress-nettstedet ditt. Koble enkelt sammen utvidelsene dine, nettstedene dine og appene dine.','Save Changes'=>'Lagre endringer','TranslatePress Errors'=>'TranslatePress-feil','There are no logged errors.'=>'Det er ingen loggførte feil.','Change language'=>'Bytt språk','Website language selector'=>'Språkvelger for nettstedet','WordPress Translation Plugin'=>'Oversettelsesutvidelse for WordPress','Available languages'=>'Tilgjengelige språk','Language Switcher update notice'=>'Oppdateringsvarsel for språkvelger','Legacy language switcher is currently enabled'=>'Eldre språkvelger er for øyeblikket aktivert','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Vi har oppgradert språkvelgeren for flere tilpasningsmuligheter og en bedre brukeropplevelse.<br>For å bruke den nye konfiguratoren må du slå av <strong>Last inn eldre språkvelger</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Merk: Du kan når som helst bytte tilbake fra <strong>Avanserte innstillinger → <a href="%s">Feilsøking</a></strong>.','Enable the new switcher'=>'Aktiver den nye bryteren','Your License Key is valid.'=>'Lisensnøkkelen din er gyldig.','Your License Key is invalid.'=>'Lisensnøkkelen din er ugyldig.','Your License has expired.'=>'Lisensen din har utløpt.','Deactivate License'=>'Deaktiver lisens','Add a license key'=>'Legg til en lisensnøkkel','License Key'=>'Lisensnøkkel','Manage your license in your %1$s.'=>'Administrer lisensen din på %1$s.','Account Page'=>'Kontoside','Don’t have a TranslatePress AI License Key?'=>'Har du ikke en TranslatePress AI-lisensnøkkel?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Du kan få en %1$sgratis%2$s ved å opprette en gratis konto. Det inkluderer:','Access to TranslatePress AI for instant automatic translations'=>'Tilgang til TranslatePress AI for umiddelbare automatiske oversettelser','2000 AI words to translate automatically'=>'2000 AI-ord å oversette automatisk','Get a free License Today'=>'Få en gratis lisens i dag','Debug Information'=>'Feilsøkingsinformasjon','Debug Data for License Checking'=>'Feilsøkingsdata for lisenskontroll','Debug Data for License Activation'=>'Feilsøkingsdata for lisensaktivering','Get more AI words and unlock all features with TranslatePress Pro.'=>'Få flere AI-ord og lås opp alle funksjoner med TranslatePress Pro.','Upgrade now ↗'=>'Oppgrader nå ↗','Already purchased a Premium version?'=>'Har du allerede kjøpt en Premium-versjon?','Go to your %1$s'=>'Gå til din %1$s','TranslatePress.com Account'=>'TranslatePress.com-konto','Download & Install the Pro plugin'=>'Last ned og installer Pro-tillegget','Learn More'=>'Les mer','Get a translation volume estimate with a detailed breakdown per page'=>'Få et overslag over oversettelsesvolum med detaljert oversikt per side','Find how many translatable words are on your website'=>'Finn ut hvor mange oversettbare ord det er på nettstedet ditt','Enable Automatic Translation'=>'Aktiver automatisk oversettelse','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'For å bruke <strong>DeepL</strong> til automatisk oversettelse, aktiver dette Pro-tillegget fra <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Automatisk oversettelse med <strong>DeepL</strong> er tilgjengelig som <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Ved å oppgradere får du tilgang til alle betalte tillegg, premium support og bidrar til å finansiere fremtidig utvikling av TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Merk at bruk av DeepL API faktureres separat. Se <a href="https://www.deepl.com/pro.html#developer">DeepL-prisinformasjon</a>.','TranslatePress Pro Add-ons'=>'TranslatePress Pro-tillegg','Test API credentials'=>'Test API-legitimasjon','Check if the selected translation engine is configured correctly.'=>'Sjekk om den valgte oversettelsesmotoren er konfigurert riktig.','Alternative Engines'=>'Alternative motorer','Switch to TranslatePress AI'=>'Bytt til TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integrer maskinoversettelse direkte med WordPress-nettstedet ditt.','More info'=>'Mer info','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Velg hvilken motor du vil bruke for å %1$s automatisk oversette nettstedet ditt.','Automatic Translation Settings'=>'Innstillinger for automatisk oversettelse','AI Words Low Notification'=>'Varsel om lavt antall AI-ord','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Motta et e-postvarsel når TranslatePress AI-ordtallet ditt faller under den angitte terskelen.','This feature is only available when using the TranslatePress AI translation engine.'=>'Denne funksjonen er kun tilgjengelig når du bruker TranslatePress AI-oversettingsmotoren.','Notification Email'=>'Varsel-e-postadresse','The email address where the low AI words notification will be sent.'=>'E-postadressen som skal motta varselet om lavt antall AI-ord.','Word Threshold'=>'Ordterskel','words'=>'ord','You will be notified when remaining AI words drop below this number.'=>'Du vil bli varslet når antallet gjenværende AI-ord faller under dette tallet.','Automatically Translate Slugs'=>'Oversett slug automatisk','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Generer automatiske oversettelser av slug for innlegg, sider og egendefinerte innleggstyper.<br/>Slug vil bli oversatt automatisk fra og med den andre oppdateringen av hver side.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Denne funksjonen er kun tilgjengelig i betalversjonen. Oppgrader TranslatePress og få tilgang til flere premiumfunksjoner.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Krever at <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack-tillegget</a> er installert og aktivert.','Upgrade now'=>'Oppgrader nå','Block Crawlers'=>'Blokker crawlere','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Hindre crawlere i å utløse automatiske oversettelser på nettstedet ditt.<br>Dette vil ikke forhindre crawlere i å få tilgang til sidene på dette nettstedet.','Limit machine translation / characters per day'=>'Begrens maskinoversettelse / tegn per dag','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Legg til en grense for antallet automatisk oversatte tegn, slik at du kan budsjettere prosjektet ditt bedre.','characters per day'=>'tegn per dag','Today\'s Character Count: '=>'Dagens tegnantall: ','Log machine translation queries.'=>'Logg maskinoversettelsesforespørsler.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Aktiver kun for testformål. Kan påvirke ytelsen.<br>Alle poster lagres i databasetabellen wp_trp_machine_translation_log. Bruk en utvidelse som <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> for å bla gjennom loggene, eller direkte fra databasebehandleren din (PHPMyAdmin, osv.)','Test API Credentials'=>'Test API-legitimasjon','HTTP Referrer: '=>'HTTP-henviser: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Bruk denne HTTP-henviseren hvis API-et lar deg begrense nøkkelbruk fra dashbordet sitt.','Response'=>'Respons','Response Body'=>'Responsbody','Entire Response From wp_remote_get():'=>'Hele responsen fra wp_remote_get():','All Languages'=>'Alle språk','Select the languages you wish to make your website available in.'=>'Velg språkene du vil gjøre nettstedet ditt tilgjengelig på.','Formality'=>'Formell stil','Code'=>'Kode','Slug'=>'Slug','Default'=>'Standard','Formal'=>'Formell','Informal'=>'Uformell','Language'=>'Språk','This language does not support formality. '=>'Dette språket støtter ikke formell stil. ','Are you sure you want to remove this language?'=>'Er du sikker på at du vil fjerne dette språket?','Custom Languages'=>'Egendefinerte språk','To Add more languages activate the Multiple Languages Addon'=>'For å legge til flere språk, aktiver tillegget Multiple Languages','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Du trenger en aktiv lisens for å legge til flere språk. Bekreft i din %1$skonto%2$s at lisensen din er gyldig.','Please %1$senter your license%2$s key first to add more languages.'=>'Vennligst %1$sskriv inn din lisens%2$s-nøkkel først for å legge til flere språk.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Å legge til mer enn to språk er en betalt funksjon. Oppgrader TranslatePress og lås opp flere premium-funksjoner.','Website Languages'=>'Nettstedsspråk','Default Language'=>'Standardspråk','Select the language your content is written in.'=>'Velg språket innholdet ditt er skrevet på.','WARNING. Changing the default language will invalidate existing translations.'=>'ADVARSEL. Endring av standardspråket vil ugyldiggjøre eksisterende oversettelser.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Dette gjelder også ved endring fra en_US til en_GB, ettersom de behandles som to forskjellige språk.','In most cases changing the default flag is all it is needed: '=>'I de fleste tilfeller er det nok å endre standardflagget: ','replace the default flag'=>'erstatt standardflagget','Re-run Setup Wizard'=>'Kjør oppsettsveiviseren på nytt','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Oppsettsveiviseren lar deg raskt sette opp TranslatePress. Du kan starte den når som helst.','Language Settings'=>'Språkinnstillinger','Use Native language name'=>'Bruk opprinnelige språknavn','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Kryss av hvis du vil vise språk med deres opprinnelige navn. Ellers vil språkene vises på engelsk.','Use a subdirectory for the default language'=>'Bruk en underkatalog for standardspråket','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Kryss av hvis du vil legge til underkatalogen i URL-en for standardspråket.</br>Ved å krysse av for dette alternativet blir standardspråket som besøkende på nettstedet ser det første i listen «Alle språk».','Force language in custom links'=>'Tving språk i egendefinerte lenker','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Velg Ja hvis du vil tvinge egendefinerte lenker uten språkkoding til å beholde det valgte språket.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Bruk shortcode på en hvilken som helst side eller widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Du kan også legge til <a href="%s" title="Dokumentasjon for språkvelgerblokken">språkvelgerblokken</a> i WP Gutenberg-editoren.','Menu item'=>'Menyelement','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Gå til  %1$s Utseende -> Menyer%2$s for å legge til språk i språkvelgeren i hvilken som helst meny.','Learn more in our documentation.'=>'Les mer i dokumentasjonen vår.','Floating language selection'=>'Flytende språkvalg','Add a floating dropdown that follows the user on every page.'=>'Legg til en flytende nedtrekksmeny som følger brukeren på alle sider.','Show "Powered by TranslatePress"'=>'Vis «Drevet av TranslatePress»','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Vis den lille «Drevet av TranslatePress»-etiketten i den flytende språkvelgeren.','5 Days to Better Multilingual Websites'=>'5 dager til bedre flerspråklige nettsteder','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sBli med på vårt GRATIS og EKSKLUSIVT onboarding-kurs%s og lær hvordan du øker den flerspråklige trafikken din, når internasjonale markeder, og sparer tid og penger – samtidig som du får mest mulig ut av TranslatePress!','Invalid email address'=>'Ugyldig e-postadresse','Your email'=>'Din e-post','Sign me up!'=>'Meld meg på!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Meld deg på med e-postadressen din og motta en e-postguide i fem deler som hjelper deg å få mest mulig ut av TranslatePress.','Dismiss email course notification'=>'Avvis varsel om e-postkurs','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hei %s,<br>Ikke gå glipp av viktige oppdateringer – meld deg på varsler om sikkerhets- og funksjonsoppdateringer, og ikke-sensitiv diagnostisk sporing.','Allow & Continue'=>'Tillat og fortsett','Skip'=>'Hopp over','This will allow TranslatePress to:'=>'Dette lar TranslatePress:','Your profile overview'=>'Oversikt over profilen din','Name and email address'=>'Navn og e-postadresse','Admin Notices'=>'Administratorvarsler','Updates, announcements, marketing, no spam'=>'Oppdateringer, kunngjøringer, markedsføring, ingen spam','Plugin status & settings'=>'Plugin-status og -innstillinger','Active, Deactivated, installed version and settings'=>'Aktiv, deaktivert, installert versjon og innstillinger','Privacy Policy'=>'Personvernerklæring','Terms of Service'=>'Tjenestevilkår','Support'=>'Støtte','Documentation'=>'Dokumentasjon','Add Extra AI Words'=>'Legg til ekstra AI-ord','Optimize TranslatePress database tables'=>'Optimaliser databasetabeller for TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>VIKTIG MERKNAD:</strong> Før du utfører denne handlingen, er det sterkt anbefalt å ta sikkerhetskopi av databasen først.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'VIKTIG: Det anbefales på det sterkeste å ta sikkerhetskopi av databasen først!! Er du sikker på at du vil fortsette?','Operations to perform'=>'Handlinger som skal utføres','Remove CDATA for original and dictionary strings'=>'Fjern CDATA for original- og ordboksstrenger','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Fjerner CDATA fra tabellene trp_original_strings og trp_dictionary_*.<br>Denne typen innhold skal ikke oppdages av TranslatePress. Det kan ha blitt introdusert i databasen i eldre versjoner av utvidelsen.','Remove untranslated links from dictionary tables'=>'Fjern uoversatte lenker fra ordbokstabeller','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Fjerner uoversatte lenker og bilder fra alle trp_dictionary_*-tabeller. Disse tabellene inneholder oversettelser for brukerinnskrevne strenger som innleggsinnhold, innleggstittel, menyer osv.','Remove duplicate rows for gettext strings'=>'Fjern duplikate rader for gettext-strenger','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Fjerner duplikate rader fra alle trp_gettext_*-tabeller. Disse tabellene inneholder oversettelser for strenger fra temaer og programtillegg.','Remove duplicate rows for dictionary strings'=>'Fjern duplikate rader for ordboksstrenger','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Fjerner duplikate rader fra alle trp_dictionary_*-tabeller. Disse tabellene inneholder oversettelser for brukerinnskrevne strenger som innleggsinnhold, innleggstittel, menyer osv.','Remove duplicate rows for original dictionary strings'=>'Fjern duplikate rader for originale ordboksstrenger','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Fjerner duplikate rader fra trp_original_strings-tabellen. Denne tabellen inneholder strenger på standardspråket, uten noen oversettelse.<br>trp_original_meta-tabellen, som inneholder metainformasjon som refererer til det overordnede innleggets ID, regenereres også.<br>Slike duplikater kan oppstå i unntakstilfeller ved uventet oppførsel.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Erstatt gettext-strenger som har original-ID satt til NULL med de korrekte original-ID-ene','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Retter opp et grensetilfelle der noen gettext-strenger har fått original-ID feilaktig satt til NULL, noe som forårsaker problemer i oversettelseseditoren.<br>Denne operasjonen korrigerer original-ID-ene i trp_gettext_*-tabellene.<br>Kryss kun av for dette alternativet hvis du har opplevd et problem i oversettelseseditoren der klikk på den grønne blyanten ikke viste gettext-strengen til oversettelse i venstre sidefelt.<br>La ellers dette alternativet være ukrysset, da det er en ressurskrevende operasjon.','Optimize Database'=>'Optimaliser database','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Oppdaterer TranslatePress-tabeller. La dette vinduet være åpent.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'De inaktive språkene vil fortsatt være synlige og aktive for administratoren. For andre brukere vil de ikke være synlige i språkvelgerne, og de vil heller ikke være tilgjengelige.','unknown'=>'ukjent','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Extra Languages-tillegget</strong> krever TranslatePress versjon %1$s eller høyere. Du bruker for øyeblikket versjon %2$s. Oppdater TranslatePress for å aktivere denne funksjonen.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Automatiske og manuelle endringer i slug-oversettelse som ble utført mens <strong>TranslatePress - Multilingual</strong> 2.8.4 var aktiv, måtte fjernes på grunn av noen problemer med den versjonen. Alle slug-oversettelser fra før den versjonen er nå i bruk. Takk for forståelsen!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Hvis du absolutt trenger dem, finnes de fjernede oversettelsene i tabellene trp_slug_original_obsolete og trp_slug_translation_obsolete.','View Docs'=>'Vis dokumentasjon','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Tilordne ulike domener eller underdomener til hvert språk. Når besøkende åpner disse domenene, laster TranslatePress den aktuelle språkoversettelsen direkte uten å omdirigere.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Eksempel: %1$s for engelsk, %2$s for spansk, %3$s for fransk.','Before enabling:'=>'Før aktivering:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Sørg for at domenene dine er registrert, pekt til serveren din, og har SSL-sertifikater konfigurert.','Domain'=>'Domene','Map this language to a different domain or sub-domain.'=>'Koble dette språket til et annet domene eller underdomene.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Forhåndsutfyll med gjeldende domene','Check DNS'=>'Sjekk DNS','Checking DNS...'=>'Sjekker DNS...','DNS is correctly configured!'=>'DNS er riktig konfigurert!','DNS check failed. Please verify your domain configuration.'=>'DNS-sjekk mislyktes. Kontroller domenekonfigurasjonen din.','This domain is already assigned to another language.'=>'Dette domenet er allerede tilordnet et annet språk.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Tillegget Different Domain per Language</strong> krever TranslatePress versjon %1$s eller høyere. Du bruker for øyeblikket versjon %2$s. Oppdater TranslatePress for å aktivere denne funksjonen.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Merk: Dette alternativet er deaktivert når tillegget Different Domain for Language er aktivt.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Domene er påkrevd når domenetilordning er aktivert. Bryteren er deaktivert for språk med tomme domener.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Det samme domenet kan ikke tilordnes flere språk. Bryteren er deaktivert for dupliserte domener.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Et språks domene kan ikke være det samme som hovednettstedets URL. Bryteren er deaktivert for det samsvarende domenet.','Please enter a domain.'=>'Skriv inn et domene.','Invalid domain format.'=>'Ugyldig domenefornat.','Could not reach domain: %s'=>'Kunne ikke nå domenet: %s','Domain returned HTTP status %d.'=>'Domenet returnerte HTTP-status %d.','Domain is reachable!'=>'Domenet er tilgjengelig!','Limit this menu item to the following languages'=>'Begrens dette menyelementet til følgende språk','Date format'=>'Datoformat','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Tilpass datoformateringen for hvert oversatte språk.<br/>La stå tomt for standard WP-innstilling, eller se mer informasjon <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">her</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'For å redigere et eksisterende TranslatePress-språk, skriv inn språkkoden og fyll ut kun kolonnene du vil overskrive (f.eks. språknavn, flagg).<br>Du kan også legge til nye egendefinerte språk. De vil være tilgjengelige under Generelle innstillinger, i listen Alle språk, der URL-slug kan redigeres.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'For egendefinert flagg, last først opp bildet i mediebiblioteket og lim deretter inn URL-en.<br>Endring eller sletting av et egendefinert språk vil påvirke oversettelser og nettstedets URL-er.<br>Språkkoden og ISO-koden skal kun inneholde alfabetiske verdier, numeriske verdier, "-" og "_".<br>ISO-kodene finnes på <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO-koder</a> og <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL målkoder</a>.','Language code'=>'Språkkode','Language name'=>'Språknavn','Native name'=>'Opprinnelig navn','ISO Code'=>'ISO-kode','Flag URL'=>'Flagg-URL','Text RTL'=>'Tekst RTL','Custom language'=>'Egendefinert språk','Disable dynamic translation'=>'Deaktiver dynamisk oversettelse','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Deaktiverer gjenkjenning av strenger som vises dynamisk ved hjelp av JavaScript. <br/>Strenger som lastes inn via et AJAX-kall på serversiden vil fortsatt bli oversatt.','Disable translation for gettext strings'=>'Deaktiver oversettelse for gettext-strenger','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext-strenger er strenger som genereres av temaer og plugins. <br> Å oversette denne typen strenger via TranslatePress kan være unødvendig hvis de allerede er oversatt ved hjelp av .po/.mo-filer. <br>Å aktivere dette alternativet kan forbedre nettstedets lasteytelse i visse tilfeller. Ulempen er at du ikke lenger kan redigere gettext-oversettelser ved hjelp av TranslatePress, eller dra nytte av automatisk oversettelse av disse strengene.','Gettext Strings translation is disabled'=>'Oversettelse av Gettext-strenger er deaktivert','To enable it go to '=>'For å aktivere det, gå til ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Avanserte innstillinger->Feilsøking->Deaktiver oversettelse for gettext-strenger',' and uncheck the Checkbox.'=>' og fjern merket i avmerkingsboksen.','Dismiss'=>'Avvis','Exclude translated links from sitemap'=>'Ekskluder oversatte lenker fra sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Inkluder ikke oversatte lenker i sitemaps generert av SEO-utvidelser.<br/>Krever at <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack-tillegg</a> er installert og aktivert.','Disable post container tags for post title'=>'Deaktiver container-koder for innleggstittel','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Det deaktiverer søkeindeksering av innleggstittelen i oversatte språk.<br/>Nyttig når tittelen på innlegget ikke tillater HTML, noe som ødelegger siden.','Disable post container tags for post content'=>'Deaktiver container-koder for innleggsinnhold','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Det deaktiverer søkeindeksering av innleggsinnholdet i oversatte språk.<br/>Nyttig når innholdet i innlegget ikke tillater HTML, noe som ødelegger siden.','Do not translate certain paths'=>'Ikke oversett visse stier','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Velg hvilke stier som kan oversettes. Støtter jokertegn på slutten av stien.<br>For eksempel, for å ekskludere https://example.com/some/path kan du enten bruke regelen /some/path/ eller /some/*.<br>Skriv inn hver regel på sin egen linje. For å ekskludere forsiden bruker du {home}.','Exclude Paths From Translation'=>'Ekskluder stier fra oversettelse','Translate Only Certain Paths'=>'Oversett kun visse stier','Enable the hreflang x-default tag for language:'=>'Aktiver hreflang x-default-taggen for språk:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Aktiverer hreflang="x-default" for et helt språk. Se dokumentasjonen for mer informasjon.','Translate numbers and numerals'=>'Oversett tall og nummeraler','Enable translation of numbers ( e.g. phone numbers)'=>'Aktiver oversettelse av tall ( f.eks. telefonnumre)','Selector'=>'Velger','Exclude from dynamic translation'=>'Ekskluder fra dynamisk oversettelse','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Strenger som finnes i HTML-noder som samsvarer med disse selektorene, skal ikke oversettes dynamisk.<br>Ekskluderer alle underelementer av HTML-noder som samsvarer med disse selektorene fra å bli oversatt ved hjelp av JavaScript.<br/>Disse strengene vil fortsatt bli oversatt på serversiden hvis det er mulig.','Gettext String'=>'Gettext-streng','Exclude Gettext Strings'=>'Ekskluder Gettext-strenger','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Ekskluder disse strengene fra å bli oversatt som Gettext-strenger av TranslatePress. La domenet stå tomt for at det skal gjelde enhver Gettext-streng.<br/>Kan fortsatt oversettes via po/mo-filer.','Exclude selectors only from automatic translation'=>'Ekskluder kun velgere fra automatisk oversettelse','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Strenger som finnes i HTML-noder som samsvarer med disse selektorene, skal ikke oversettes automatisk.<br>Ekskluderer alle underelementer av HTML-noder som samsvarer med disse selektorene fra å bli oversatt automatisk.<br>Manuell oversettelse av disse strengene er fortsatt mulig.','Exclude selectors from translation'=>'Ekskluder velgere fra oversettelse','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Strenger som finnes i HTML-noder som samsvarer med disse selektorene, skal ikke oversettes.<br>Ekskluderer alle underelementer av HTML-noder som samsvarer med disse selektorene fra å bli oversatt.<br>Disse strengene kan ikke oversettes manuelt eller automatisk.','String'=>'Streng','Exclude strings from automatic translation'=>'Ekskluder strenger fra automatisk oversettelse','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Oversett ikke disse strengene automatisk (f.eks. navn, tekniske ord...)<br>Avsnitt som inneholder disse strengene, vil fortsatt bli oversatt, bortsett fra den angitte delen.','Fix broken HTML'=>'Reparer ødelagt HTML','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Generelt forsøk på å reparere ødelagt eller manglende HTML på oversatte sider.<br/>','Force slash at end of home url:'=>'Tving frem skråstrek på slutten av hjemme-URL:','Ads a slash at the end of the home_url() function'=>'Legger til en skråstrek på slutten av home_url()-funksjonen','Show Both (recommended)'=>'Vis begge (anbefalt)','Remove Country Locale'=>'Fjern landslokalitet','Remove Region Independent Locale'=>'Fjern regionuavhengig lokalitet','Remove duplicate hreflang'=>'Fjern duplisert hreflang','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Velg hvilke hreflang-koder som skal vises på nettstedet ditt.<br/>Vi anbefaler å vise begge typer hreflang-koder som angitt i <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Googles dokumentasjon</a>.<br/>Fjerning av Landlokalitet når du har flere Landlokaliteter for samme språk (f.eks. engelsk (Storbritannia) og engelsk (USA)) vil resultere i at det vises én hreflang-kode med lenke til bare én av regionlokalitetene for det språket.','Default (example: en-US, fr-CA, etc.)'=>'Standard (eksempel: en-US, fr-CA, osv.)','Regional (example: en, fr, es, etc.)'=>'Regional (eksempel: en, fr, es, osv.)','HTML Lang Attribute Format'=>'Format for HTML-språkattributt','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Endre lang-attributtet i html-taggen til et format som inkluderer land/region eller ikke. <br>I HTML skal lang-attributtet (<html lang="en-US">) brukes for å angi språket til tekstinnholdet, slik at nettleseren kan vise eller behandle innholdet ditt korrekt (f.eks. for orddeling, styling, stavekontroll, osv).','Load legacy Language Switcher'=>'Last inn eldre språkvelger','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Gjelder for alle typer språkvelgere (flytende, shortcode og meny). Når dette er aktivert, vil nettstedet gå tilbake til å bruke den opprinnelige språkvelgeren konfigurert i fanen Generelle innstillinger, og erstatte den nye tilpassbare versjonen. De eksisterende innstillingene for språkvelgeren vil fortsatt være lagret, men de vil bli ignorert mens dette alternativet er aktivt.','Load legacy SEO Pack Add-On'=>'Last inn eldre SEO Pack-tillegg','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Hvis den nylige migreringen til den nye slug-omskrivingen skaper problemer, sett dette til Ja for å bruke den gamle metoden <br> Vennligst <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">åpne en support-sak</a> og gi oss beskjed om problemene du opplever.','Manual Translation Only'=>'Kun manuell oversettelse','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress skanner og lagrer strenger i databasen proaktivt når brukere besøker oversatte sider. <br>Denne innstillingen deaktiverer denne funksjonaliteten og tillater kun oversettelse og lagring av strenger når du er inne i oversettelseseditoren. <br>Deaktiverer også maskinoversettelse utenfor oversettelseseditoren, noe som gir deg bedre kontroll over tegnforbruk, ved å kun oversette sidene du besøker i oversettelseseditoren.','Open language switcher only on click'=>'Åpne språkvelgeren kun ved klikk','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Åpne språkvelger-shortcoden ved å klikke på den i stedet for å holde pekeren over den.<br> Lukk den ved å klikke på den, et hvilket som helst annet sted på skjermen eller ved å trykke på escape-tasten. Dette vil kun påvirke språkvelger-shortcoden.','Show opposite language in the language switcher'=>'Vis motsatt språk i språkvelgeren','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Gjør språkvelgeren om til en knapp som viser det andre tilgjengelige språket, ikke det gjeldende.<br> Fungerer kun når det er nøyaktig to språk, standardspråket og et oversettelsesspråk.<br>Dette vil også påvirke språkvelger-shortcoden og den flytende språkvelgeren.<br> For å oppnå dette i menyspråkvelgeren går du til Utseende->Menyer->Språkvelger og velger Motsatt språk.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Klikk her</a> for å få tilgang til databaseoptimaliseringsverktøyet.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Det hjelper deg med å fjerne mulige dupliserte oversettelser, rydde opp i unødvendige data og reparere mulige metadata-problemer.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Her</a> kan du se de siste 5 SQL-feilene som er relevante for TranslatePress, hvis de finnes.','Troubleshooting'=>'Feilsøking','Exclude Gettext strings'=>'Ekskluder Gettext-strenger','Debug'=>'Debug','Custom languages'=>'Egendefinerte språk','Miscellaneous options'=>'Diverse alternativer','Exclude strings & pages'=>'Ekskluder strenger og sider','Automatic Translation Memory'=>'Automatisk oversettelsesminne','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Bruk samme oversettelse for liknende tekst. Strengene må ha en likhetsprosent på 95 %.<br>Hjelper med å forhindre tap av eksisterende oversettelse ved retting av skrivefeil eller mindre justeringer av originalteksten. <br>Hvis det allerede finnes en oversettelse for en svært lik originalstreng, vil den automatisk bli brukt for den gjeldende originalstrengen.<br>Fungerer ikke ved endringer av en tekst som er en del av en oversettelsesblokk, med mindre den nye teksten manuelt flettes inn igjen i en oversettelsesblokk.<br>Hver streng må ha minimum 50 tegn.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'ADVARSEL: Denne funksjonen kan påvirke sidelastingstiden negativt for sekundærspråk, spesielt med store databaser (for eksempel nettsteder med mange sider eller produkter). Hvis du opplever treg lasting, deaktiver denne og prøv igjen.','Fix missing dynamic content'=>'Fiks manglende dynamisk innhold','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Kan hjelpe med å fikse manglende innhold satt inn med JavaScript. <br> Den viser dynamisk innsatt innhold på originalspråket et øyeblikk før oversettelsesforespørselen er fullført.','Filter Gettext wrapping from post content and title'=>'Filtrer Gettext-innpakking fra innleggsinnhold og -tittel','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrerer Gettext-innpakking som #!trpst#trp-gettext fra alt oppdatert innleggsinnhold og alle oppdaterte innleggstitler. Påvirker ikke tidligere innleggsinnhold. <br/><strong>Databasebackup anbefales før du aktiverer.</strong>','Filter Gettext wrapping from post meta'=>'Filtrer Gettext-innpakking fra innleggsmeta','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrerer Gettext-innpakking som #!trpst#trp-gettext fra all oppdatert innleggsmeta. Påvirker ikke tidligere innleggsmeta. <br/><strong>Databasebackup anbefales før du aktiverer.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Google Translate API-nøkkel','Add your API Key here...'=>'Legg til API-nøkkelen din her...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Besøk <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">denne lenken</a> for å se hvordan du kan sette opp en API-nøkkel, <strong>kontrollere API-kostnader</strong> og angi HTTP referrer-begrensninger.','Your HTTP referrer is: %s'=>'Din HTTP referrer er: %s','There was an error on the server processing your Google Translate key.'=>'Det oppstod en feil på serveren ved behandling av Google Translate-nøkkelen din.','There was an error with your Google Translate key.'=>'Det oppstod en feil med Google Translate-nøkkelen din.','Please check your TranslatePress license key.'=>'Sjekk TranslatePress-lisensnøkkelen din.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Ingen aktiv lisens oppdaget for dette nettstedet.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'For å aktivere automatisk oversettelse med TranslatePress AI trenger du en lisensnøkkel som du får ved å opprette en gratis konto.','Create your Free Account'=>'Opprett gratis konto',' or '=>' eller ','Enter your license key'=>'Skriv inn lisensnøkkelen din',' Or %1$spurchase one here%2$s'=>' Eller %1$skjøp en her%2$s','Your free account includes: '=>'Din gratis konto inkluderer: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Få flere AI-ord og lås opp alle AI-funksjoner med TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Du har en gyldig %s <strong>lisens</strong>.',' words remaining. '=>' ord igjen. ','Recheck'=>'Sjekk på nytt','Rechecking...'=>'Sjekker på nytt...','Done.'=>'Ferdig.','Manage your license & quota on the %s'=>'Administrer lisensen og kvoten din på %s','TranslatePress.com Account Page'=>'TranslatePress.com-kontosiden','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-støtte for side-slug, sidetittel, beskrivelse og sosial graf-informasjon for Facebook og Twitter. HTML lang-attributtet er satt riktig.','Enable Modules'=>'Aktiver moduler','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Aktiver tilleggsmoduler for å utvide TranslatePress og forbedre funksjonaliteten på det oversatte nettstedet ditt.','More functionality with TranslatePress Pro.'=>'Mer funksjonalitet med TranslatePress Pro.','Already a Pro User?'=>'Er du allerede Pro-bruker?','Activate License Key'=>'Aktiver lisensnøkkel','This add-on is not available on your current plan.'=>'Dette tillegget er ikke tilgjengelig i din nåværende plan.','Continue'=>'Fortsett','The link you followed has expired. Please reload the page and try again.'=>'Lenken du fulgte har utløpt. Last sid